import json
from datetime import datetime, timezone
from pathlib import Path
import fcntl  # file-level lock prevents concurrent write corruption

AUDIT_LOG = Path("/var/data/consent/audit_trail.jsonl")

def append_event(event_type: str, payload: dict) -> None:
    """Append one audit event to the immutable log. Thread-safe via file lock."""
    record = {
        "event_type": event_type,
        "recorded_at": datetime.now(timezone.utc).isoformat(),
        **payload,
    }
    line = json.dumps(record, default=str) + "\n"

    with open(AUDIT_LOG, "a", encoding="utf-8") as f:
        fcntl.flock(f, fcntl.LOCK_EX)
        f.write(line)
        f.flush()
        fcntl.flock(f, fcntl.LOCK_UN)


# Typed helpers for each event type

def log_consent_granted(consent_id, user_id, feature_id, legal_basis,
                         consent_version, granted_at, scope, ui_element, source_ip=""):
    append_event("consent_granted", {
        "consent_id": consent_id, "user_id": user_id, "feature_id": feature_id,
        "legal_basis": legal_basis, "consent_version": consent_version,
        "granted_at": granted_at, "scope": scope,
        "ui_element": ui_element, "source_ip": source_ip,
    })

def log_consent_withdrawn(consent_id, user_id, feature_id, withdrawn_at):
    append_event("consent_withdrawn", {
        "consent_id": consent_id, "user_id": user_id,
        "feature_id": feature_id, "withdrawn_at": withdrawn_at,
    })

def log_api_invocation(consent_id, user_id, feature_id, model: str):
    append_event("api_invocation", {
        "consent_id": consent_id, "user_id": user_id,
        "feature_id": feature_id,
        "invoked_at": datetime.now(timezone.utc).isoformat(),
        "model": model,
    })
